// Chat.jsx - With Domain Selection Feature
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import s from './Chat.module.css';

const T = {
  fr: {
    newChat: 'Nouveau chat', today: "Aujourd'hui", days30: '30 derniers jours',
    settings: 'Paramû´tres', signOut: 'Dûˋconnexion',
    welcomeTitle: 'Bienvenue sur AI Advisor',
    welcomeSub: 'Votre assistant intelligent pour la performance des campagnes, la qualitûˋ des utilisateurs et les dûˋcisions de croissance.',
    examples: 'Exemples', capabilities: 'Capacitûˋs', limitations: 'Limites',
    ex1: 'Quelle campagne a eu le meilleur ROI ces 30 derniers jours ?',
    ex2: 'Comparez la rûˋtention entre iOS et Android en Europe',
    ex3: 'Quels segments d\'audience chutent aprû´s le jour 7 ?',
    cap1: 'Analyser les tendances de performance des campagnes',
    cap2: 'Recommander des rûˋallocations budgûˋtaires',
    cap3: 'Prûˋvoir LTV, rûˋtention et ROAS',
    lim1: 'Les donnûˋes doivent ûˆtre disponibles dans votre tableau de bord',
    lim2: 'Les suggestions IA sont basûˋes sur vos donnûˋes',
    lim3: 'Toujours revoir les recommandations avant application',
    placeholder: 'Demandez tout ce qui concerne vos campagnes...',
    hint: 'Entrûˋe pour envoyer ôñ Shift+Entrûˋe pour nouvelle ligne',
    theme: 'Thû´me', light: 'Clair', dark: 'Sombre', language: 'Langue',
    domains: 'Domaines d\'expertise',
    domainSante: 'Santûˋ',
    domainEducation: 'ûducation',
    domainTech: 'Technologie',
    domainBusiness: 'Business',
    domainLegal: 'Juridique',
    domainMarketing: 'Marketing',
    selectDomain: 'Sûˋlectionnez un domaine pour commencer',
