export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();
  const [language, setLanguage] = useState('fr');
  const [showSettings, setShowSettings] = useState(false);
  const [showDomains, setShowDomains] = useState(true);
  const [selectedDomain, setSelectedDomain] = useState(null);
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);
  const t = T[language];

  const getDomainName = (domainId) => {
    const domain = DOMAINS[domainId];
    return domain ? t[domain.nameKey] : domainId;
  };

  const examples = [t.ex1, t.ex2, t.ex3];
  const capabilities = [t.cap1, t.cap2, t.cap3];
  const limitations = [t.lim1, t.lim2, t.lim3];

  useEffect(() => {
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  useEffect(() => { loadConversations(); }, []);
  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const loadConversations = async () => {
    try {
      const r = await axios.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch {}
  };

  const loadConversation = async (convId) => {
    try {
      const r = await axios.get(`/conversations/${convId}/messages`);
      const conv = conversations.find(c => c.id === convId);
      if (conv?.domain) setSelectedDomain(conv.domain);
      setMessages(r.data.messages.map(m => ({ 
        role: m.sender === 'user' ? 'user' : 'bot', 
        content: m.content 
      })));
      setActiveConvId(convId);
      setShowDomains(false);
    } catch {}
  };

  const deleteConversation = async (id, e) => {
    e.stopPropagation();
    try {
      await axios.delete(`/conversations/${id}`);
      setConversations(prev => prev.filter(c => c.id !== id));
      if (activeConvId === id) { 
        setActiveConvId(null); 
        setMessages([]);
        setSelectedDomain(null);
        setShowDomains(true);
      }
    } catch {}
  };

  const newConversation = () => { 
    setActiveConvId(null); 
    setMessages([]);
    setSelectedDomain(null);
    setShowDomains(true);
    textareaRef.current?.focus(); 
  };

  const selectDomain = (domainId) => {
    const domain = DOMAINS[domainId];
    setSelectedDomain(domainId);
    setShowDomains(false);

    // Auto-send domain introduction message
    const domainMessage = `${domain.prompt}${domain.defaultMessage}`;
    setInput(domainMessage);
    setTimeout(() => {
      sendMessageWithDomain(domainMessage, domainId);
    }, 100);
  };

  const sendMessageWithDomain = async (messageText, domainId = selectedDomain) => {
    if (!messageText.trim() || loading) return;

    setMessages(prev => [...prev, { role: 'user', content: messageText }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);

    try {
      const r = await axios.post('/chat', { 
        message: messageText, 
        conversation_id: activeConvId,
        domain: domainId // Send domain to backend
      });
      setMessages(prev => [...prev, { role: 'bot', content: r.data.response }]);
      if (!activeConvId && r.data.conversation_id) { 
        setActiveConvId(r.data.conversation_id); 
        loadConversations();
      }
    } catch {
      setMessages(prev => [...prev, { role: 'bot', content: language === 'fr' ? 'Erreur de connexion. Veuillez rûˋessayer.' : 'Connection error. Please try again.' }]);
    } finally { 
      setLoading(false);
    }
  };

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading) return;
    await sendMessageWithDomain(text, selectedDomain);
  };

  const handleInputChange = e => {
    setInput(e.target.value);
    e.target.style.height = 'auto';
    e.target.style.height = Math.min(e.target.scrollHeight, 200) + 'px';
  };

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      sendMessage(); 
    }
  };

  const now = new Date();
  const grouped = conversations.reduce((acc, c) => {
    const d = new Date(c.updated_at || c.created_at);
    const diff = (now - d) / 86400000;
    if (diff < 1) acc.today.push(c);
    else if (diff < 30) acc.days30.push(c);
    return acc;
  }, { today: [], days30: [] });

  return (
    <div className={s.layout}>
      {/* Settings Modal */}
      {showSettings && (
        <div className={s.modalOverlay} onClick={() => setShowSettings(false)}>
          <div className={s.modal} onClick={e => e.stopPropagation()}>
            <div className={s.modalHeader}>
              <h3>{t.settings}</h3>
              <button className={s.closeModal} onClick={() => setShowSettings(false)}>û</button>
            </div>
            <div className={s.modalBody}>
              <div className={s.settingItem}>
                <span>{t.language}</span>
                <div className={s.langOptions}>
                  {['fr','en','ar'].map(l => (
                    <button key={l} onClick={() => setLanguage(l)} className={`${s.langOptionBtn} ${language === l ? s.langOptionActive : ''}`}>
                      {l.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideHeader}>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
            {t.newChat}
          </button>
        </div>
        <div className={s.sideContent}>
          {grouped.today.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.today}</div>
              {grouped.today.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <span className={s.domainIcon}>{DOMAINS[c.domain]?.icon || 'Þ˜'}</span>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>û</button>
                </div>
              ))}
            </div>
          )}
          {grouped.days30.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.days30}</div>
              {grouped.days30.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <span className={s.domainIcon}>{DOMAINS[c.domain]?.icon || 'Þ˜'}</span>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>û</button>
                </div>
              ))}
            </div>
          )}
        </div>
        <div className={s.sideFooter}>
          <button className={s.userBtn} onClick={() => setShowSettings(true)}>
            <div className={s.userAvatar}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{user?.username || 'User'}</div>
              <div className={s.userEmail}>{user?.email || ''}</div>
            </div>
          </button>
          <button className={s.signOutBtn} onClick={() => { logout(); nav('/'); }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/>
            </svg>
            {t.signOut}
          </button>
        </div>
      </aside>

      {/* Main */}
      <main className={s.main}>
        <div className={s.mainHeader}>
          <div className={s.headerLeft}>
            <button className={s.menuBtn} onClick={() => setSidebarOpen(v => !v)}>ã¯</button>
            <div className={s.headerLogo}>
              <img src="/logo.png" alt="Logo" width={26} />
              <span>AWAL GPT</span>
              {selectedDomain && (
                <span className={s.domainBadge} style={{ backgroundColor: DOMAINS[selectedDomain]?.color }}>
                  {DOMAINS[selectedDomain]?.icon} {getDomainName(selectedDomain)}
                </span>
              )}
            </div>
          </div>
          <div className={s.headerActions}>
            {['fr','en','ar'].map(l => (
              <button key={l} onClick={() => setLanguage(l)} className={`${s.langBtn} ${language === l ? s.langActive : ''}`}>
                {l.toUpperCase()}
              </button>
            ))}
            <button className={s.langBtn} onClick={() => setShowSettings(true)}>ãÿ¡</button>
          </div>
        </div>

        <div className={s.messagesArea}>
          <div className={s.messages}>
            {messages.length === 0 && showDomains ? (
              <div className={s.domainSelection}>
                <div className={s.domainHeader}>
                  <img src="/logo.png" alt="Logo" className={s.domainLogo} />
                  <h2>{t.selectDomain || "Sûˋlectionnez un domaine d'expertise"}</h2>
                  <p>Choisissez un domaine pour recevoir des rûˋponses spûˋcialisûˋes</p>
                </div>
                <div className={s.domainGrid}>
                  {Object.entries(DOMAINS).map(([id, domain]) => (
                    <button 
                      key={id}
                      className={s.domainCard}
                      onClick={() => selectDomain(id)}
                      style={{ borderLeftColor: domain.color }}
                    >
                      <div className={s.domainCardIcon} style={{ backgroundColor: `${domain.color}20`, color: domain.color }}>
                        {domain.icon}
                      </div>
                      <div className={s.domainCardContent}>
                        <h3>{t[domain.nameKey]}</h3>
                        <p>{domain.defaultMessage.substring(0, 60)}...</p>
                      </div>
                    </button>
                  ))}
                </div>
                <div className={s.domainExamples}>
                  <p>Ou commencez directement avec un exemple :</p>
                  <div className={s.exampleChips}>
                    {examples.slice(0, 3).map((ex, i) => (
                      <button key={i} className={s.exampleChip} onClick={() => setInput(ex)}>
                        {ex}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            ) : messages.length === 0 && !showDomains && selectedDomain ? (
              <div className={s.welcome}>
                <div className={s.welcomeDomainIcon} style={{ backgroundColor: DOMAINS[selectedDomain]?.color + '20' }}>
                  {DOMAINS[selectedDomain]?.icon}
                </div>
                <h1 className={s.welcomeTitle}>Domaine sûˋlectionnûˋ : {getDomainName(selectedDomain)}</h1>
                <p className={s.welcomeSub}>
                  Je suis votre expert en {getDomainName(selectedDomain)}. 
                  Posez-moi vos questions, je vous rûˋpondrai avec prûˋcision.
                </p>
                <div className={s.domainExamplesList}>
                  <h4>Questions suggûˋrûˋes :</h4>
                  <div className={s.exampleGrid}>
                    {DOMAINS[selectedDomain].examples.map((ex, i) => (
                      <button key={i} className={s.suggestionBtn} onClick={() => setInput(ex)}>
                        {ex}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div key={idx} className={s.message}>
                  <div className={s.messageAvatar}>
                    {msg.role === 'user'
                      ? <div className={s.userAvatarMsg}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
                      : <div className={s.botAvatar}>
                          <span className={s.botDomainIcon}>{DOMAINS[selectedDomain]?.icon || 'ÞÊ'}</span>
                        </div>
                    }
                  </div>
                  <div className={s.messageContent}>
                    <div className={s.messageName}>
                      {msg.role === 'user' ? (user?.username || 'You') : `AI Advisor ${selectedDomain ? `(${getDomainName(selectedDomain)})` : ''}`}
                    </div>
                    <div className={s.messageText}>{msg.content}</div>
                  </div>
                </div>
              ))
            )}
            {loading && (
              <div className={s.message}>
                <div className={s.messageAvatar}>
                  <div className={s.botAvatar}>
                    <span>{DOMAINS[selectedDomain]?.icon || 'ÞÊ'}</span>
                  </div>
                </div>
                <div className={s.messageContent}>
                  <div className={s.messageName}>AI Advisor</div>
                  <div className={s.typing}><span /><span /><span /></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>

        <div className={s.inputArea}>
          <div className={s.inputContainer}>
            {selectedDomain && (
              <div className={s.activeDomainBar} style={{ borderLeftColor: DOMAINS[selectedDomain]?.color }}>
                <span className={s.activeDomainIcon}>{DOMAINS[selectedDomain]?.icon}</span>
                <span>Expert {getDomainName(selectedDomain)}</span>
                <button className={s.changeDomainBtn} onClick={() => { 
                  setSelectedDomain(null); 
                  setShowDomains(true);
                  setMessages([]);
                }}>
                  Changer
                </button>
              </div>
            )}
            <div className={s.inputBox}>
              <textarea
                ref={textareaRef}
                className={s.textarea}
                placeholder={selectedDomain ? `Posez votre question sur ${getDomainName(selectedDomain)}...` : t.placeholder}
                value={input}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                rows={1}
                disabled={loading}
              />
              <button className={s.sendBtn} onClick={sendMessage} disabled={loading || !input.trim()}>
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
                </svg>
              </button>
            </div>
            <div className={s.inputHint}>{t.hint}</div>
          </div>
        </div>
      </main>
    </div>
